from flask import Flask, jsonify, request
from flasgger import Swagger, swag_from

app = Flask(__name__)
swagger = Swagger(app)

@app.route('/')
def index():
    """
    Kök dizin
    Bu API'nin ana sayfasıdır.
    ---
    responses:
      200:
        description: Başarılı bir karşılama mesajı
    """
    return "API Çalışıyor! Swagger UI için /apidocs adresine gidin."

@app.route('/hello/<name>', methods=['GET'])
@swag_from({
    'parameters': [
        {
            'name': 'name',
            'in': 'path',
            'type': 'string',
            'required': True,
            'description': 'Karşılanacak kişinin adı.'
        }
    ],
    'responses': {
        200: {
            'description': 'Kişiyi karşılayan mesaj.',
            'schema': {
                'type': 'object',
                'properties': {
                    'message': {
                        'type': 'string'
                    }
                }
            }
        },
        400: {
            'description': 'Geçersiz istek.'
        }
    },
    'tags': ['Selamlaşma']
})
def say_hello(name):
    """
    Bir kişiye merhaba de
    Bu uç nokta, verilen ismi kullanarak bir kişiyi karşılar.
    ---
    """
    if not name:
        return jsonify({"error": "İsim belirtilmedi"}), 400
    return jsonify({"message": f"Merhaba, {name}!"})

@app.route('/greet', methods=['POST'])
@swag_from({
    'parameters': [
        {
            'name': 'body',
            'in': 'body',
            'required': True,
            'schema': {
                'id': 'GreetingInput',
                'required': ['name'],
                'properties': {
                    'name': {
                        'type': 'string',
                        'description': 'Karşılanacak kişinin adı.',
                        'default': 'Dünya'
                    },
                    'message': {
                        'type': 'string',
                        'description': 'Özel bir mesaj.',
                        'default': 'Merhaba'
                    }
                }
            }
        }
    ],
    'responses': {
        200: {
            'description': 'Başarılı bir karşılama cevabı.',
            'schema': {
                'id': 'GreetingResponse',
                'properties': {
                    'full_message': {
                        'type': 'string'
                    }
                }
            }
        },
        400: {
            'description': 'Eksik veya geçersiz giriş.'
        }
    },
    'tags': ['Selamlaşma']
})
def greet_person():
    """
    Bir kişiyi özel bir mesajla karşıla
    POST isteği ile bir isim ve isteğe bağlı bir mesaj göndererek kişiyi karşılar.
    ---
    """
    data = request.get_json()
    if not data or 'name' not in data:
        return jsonify({"error": "İsim gerekli"}), 400

    name = data['name']
    message_prefix = data.get('message', 'Merhaba')
    full_message = f"{message_prefix}, {name}!"
    return jsonify({"full_message": full_message})

if __name__ == '__main__':
    app.run(debug=True)
